chrome.runtime.onInstalled.addListener(()=>{chrome.contextMenus.removeAll(()=>{chrome.contextMenus.create({id:"inline-analyze-risk",title:"Analyze page risk (Inline)",contexts:["page"]})})});chrome.contextMenus.onClicked.addListener((e,t)=>{e.menuItemId!=="inline-analyze-risk"||t?.id==null||chrome.tabs.sendMessage(t.id,{type:"INLINE_PAGE_RISK"}).catch(()=>{})});chrome.runtime.onInstalled.addListener(()=>{chrome.contextMenus.create({id:"inline-root",title:"Inline",contexts:["selection"]}),chrome.contextMenus.create({id:"notes",parentId:"inline-root",title:"📝 Add Note",contexts:["selection"]}),chrome.contextMenus.create({id:"highlight",parentId:"inline-root",title:"🖊️ Highlight",contexts:["selection"]}),chrome.contextMenus.create({id:"rewrite",parentId:"inline-root",title:"✏️ Rewrite",contexts:["selection"]}),chrome.contextMenus.create({id:"ai",parentId:"inline-root",title:"✨ Ask AI",contexts:["selection"]})});chrome.contextMenus.onClicked.addListener((e,t)=>{!t?.id||e.menuItemId==="inline-root"||chrome.tabs.sendMessage(t.id,{type:"INLINE_FEATURE",featureId:e.menuItemId,selectedText:e.selectionText??""})});
